using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpRestServer;

/// <summary>
/// MCP tools that wrap the Open-Meteo weather REST API.
/// Constructor parameters are resolved from DI — here, a typed HttpClient.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools(HttpClient httpClient)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { PropertyNameCaseInsensitive = true };

    [McpServerTool, Description("Get current weather for a latitude/longitude coordinate.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude (-90 to 90)")] double latitude,
        [Description("Longitude (-180 to 180)")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.open-meteo.com/v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        using var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        using var doc = JsonDocument.Parse(json);
        var current = doc.RootElement.GetProperty("current");

        var temp = current.GetProperty("temperature_2m").GetDouble();
        var wind = current.GetProperty("wind_speed_10m").GetDouble();

        return $"Temperature: {temp}°C, Wind: {wind} km/h";
    }

    [McpServerTool, Description("Look up geocoordinates for a city name.")]
    public async Task<string> GeocodeCityName(
        [Description("City name to geocode")] string city,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://geocoding-api.open-meteo.com/v1/search?name={Uri.EscapeDataString(city)}&count=1";

        using var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        using var doc = JsonDocument.Parse(json);

        if (!doc.RootElement.TryGetProperty("results", out var results)
            || results.GetArrayLength() == 0)
        {
            return $"No results found for '{city}'.";
        }

        var first = results[0];
        var name = first.GetProperty("name").GetString();
        var lat = first.GetProperty("latitude").GetDouble();
        var lon = first.GetProperty("longitude").GetDouble();
        var country = first.TryGetProperty("country", out var c) ? c.GetString() : "Unknown";

        return $"{name}, {country} — lat: {lat}, lon: {lon}";
    }
}

using McpRestServer;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;

var builder = Host.CreateApplicationBuilder(args);

builder.Services
    .AddHttpClient<WeatherTools>(client =>
    {
        client.DefaultRequestHeaders.Add("User-Agent", "McpRestServer/1.0");
    });

builder.Services
    .AddMcpServer(options =>
    {
        options.ServerInfo.Name = "weather";
        options.ServerInfo.Version = "1.0.0";
    })
    .WithStdioServerTransport()
    .WithTools<WeatherTools>();

await builder.Build().RunAsync();

